import pygame
import sys
import random
import math
import ctypes
import os

# ��ʼ��
pygame.init()
pygame.mixer.init() # Ԥ����Ч�ӿ�

# ��Ļ����
SCREEN_WIDTH, SCREEN_HEIGHT = 1920, 1080
FPS = 60

# ��ɫ
WHITE = (255, 255, 255)
BLACK = (0, 0, 0)
BUBBLE_COLOR = (255, 255, 255)

# ȫ�ֱ���
TOPMOST = True

# ��������
os.environ['SDL_VIDEO_WINDOW_POS'] = "0,0"
screen = pygame.display.set_mode((SCREEN_WIDTH, SCREEN_HEIGHT), pygame.NOFRAME | pygame.SRCALPHA)
pygame.display.set_caption("Desktop Pet")

# ���ô���͸������ (Windows)
if sys.platform == 'win32':
    hwnd = pygame.display.get_wm_info()['window']
    # ���÷ֲ㴰��
    ctypes.windll.user32.SetWindowLongPtrW(hwnd, -20, 0x00080000 | 0x00000008) # WS_EX_LAYERED | WS_EX_TOPMOST
    ctypes.windll.user32.SetLayeredWindowAttributes(hwnd, 0x00000000, 255, 0x02) # ��ɫ͸����
    ctypes.windll.user32.SetWindowPos(hwnd, -1, 0, 0, 0, 0, 0x0001 | 0x0002 | 0x0040) # �ö�

clock = pygame.time.Clock()
font = pygame.font.SysFont("simhei", 18)

# ================= �����޸ģ�ͼƬ���� =================
def load_image_from_base64(base64_string):
    """��Base64�ַ�������ͼƬ"""
    try:
        import base64
        from io import BytesIO
        
        # ��ȫBase64ͷ�����������ʱ©�˵Ļ���
        if "base64," not in base64_string:
            data = base64_string
        else:
            data = base64_string.split("base64,")[1]
            
        image_data = base64.b64decode(data)
        return pygame.image.load(BytesIO(image_data))
    except Exception as e:
        print(f"ͼƬ����ʧ��: {e}")
        #  fallback: ����һ����ɫ�������
        surf = pygame.Surface((100, 100))
        surf.fill((255, 0, 0))
        return surf

# --- ������ճ����� Base64 ���� ---
try:
    # �뽫�����ڵ������滻Ϊ��ղŸ��Ƶĳ��ַ���
    base64_cat_code = "" 
    original_image = load_image_from_base64(base64_cat_code)
except:
    # �ݴ������ûճ��������һ��Ĭ�ϵİ�ɫ����
    print("���棺δ��⵽Base64ͼƬ���룬ʹ��Ĭ�Ϸ�����档")
    original_image = pygame.Surface((150, 150))
    original_image.fill((255, 255, 255))

class DesktopPet:
    def __init__(self):
        self.scale = 1.0
        self.image = original_image
        self.width = int(self.image.get_width() * self.scale)
        self.height = int(self.image.get_height() * self.scale)
        self.x = SCREEN_WIDTH // 2 - self.width // 2
        self.y = SCREEN_HEIGHT // 2 - self.height // 2
        self.dragging = False
        self.offset_x = 0
        self.offset_y = 0
        
        # ����״̬
        self.state = "idle" # idle, jumping, squishing, shaking
        self.vel_y = 0
        self.gravity = 0.8
        self.bounce_count = 0
        self.shake_timer = 0
        self.squish_timer = 0
        
        # �Ի�����
        self.show_bubble = False
        self.bubble_text = ""
        self.bubble_timer = 0
        
        # �����ı���
        self.texts = [
            "��~", "����ҲҪ����Ŷ", "�������", "����ͷ",
            "����������", "����͵��", "����...", "β��ҡһҡ",
            "����һֻС����", "����һ��С����", "������"
        ]

    def handle_event(self, event):
        if event.type == pygame.MOUSEBUTTONDOWN:
            if event.button == 1: # ���
                mouse_x, mouse_y = event.pos
                if self.x <= mouse_x <= self.x + self.width and self.y <= mouse_y <= self.y + self.height:
                    self.dragging = True
                    self.offset_x = mouse_x - self.x
                    self.offset_y = mouse_y - self.y
                    self.trigger_interaction("click")
                else:
                    self.dragging = False
                    
            elif event.button == 3: # �Ҽ�
                self.show_context_menu()
                
            elif event.button == 4: # ������
                self.resize(1.1)
            elif event.button == 5: # ������
                self.resize(0.9)
                
        elif event.type == pygame.MOUSEBUTTONUP:
            if event.button == 1:
                self.dragging = False
                
        elif event.type == pygame.KEYDOWN:
            if event.key == pygame.K_ESCAPE:
                pygame.quit()
                sys.exit()
            elif event.key == pygame.K_t: # �� T �л��ö�
                self.toggle_topmost()

    def trigger_interaction(self, source):
        if self.state != "idle": return
        
        action = random.choice(["jump", "squish", "shake"])
        self.state = action
        
        # ��ʾ����
        self.show_bubble = True
        self.bubble_text = random.choice(self.texts)
        self.bubble_timer = 180 # 3��
        
        if action == "jump":
            self.vel_y = -20
        elif action == "squish":
            self.squish_timer = 20
        elif action == "shake":
            self.shake_timer = 30

    def show_context_menu(self):
        # ģ���Ҽ��˵�����
        # �����ǵ��ļ�����GUI�⣬������״̬��ģ�⼸������
        # ʵ��Ӧ���п��Ե��� tkinter ���ײ˵�������Ϊ��������ֱ���ڿ���̨��ӡ��ʾ
        print("[�˵�] �����Ѵ��� (���ڴ������޸��Ҽ��߼�)")
        # ʾ�����Ҽ��������è��һ��
        self.trigger_interaction("menu")

    def toggle_topmost(self):
        global TOPMOST
        TOPMOST = not TOPMOST
        if sys.platform == 'win32':
            hwnd = pygame.display.get_wm_info()['window']
            ctypes.windll.user32.SetWindowPos(hwnd, -1 if TOPMOST else -2, 0, 0, 0, 0, 0x0001 | 0x0002 | 0x0040)

    def resize(self, factor):
        self.scale *= factor
        self.scale = max(0.2, min(self.scale, 3.0)) # ���ƴ�С 20% - 300%
        new_w = int(original_image.get_width() * self.scale)
        new_h = int(original_image.get_height() * self.scale)
        
        # ��������ͼ��
        self.image = pygame.transform.scale(original_image, (new_w, new_h))
        self.width, self.height = new_w, new_h

    def update(self):
        # ��ק�߼�
        if self.dragging:
            mouse_x, mouse_y = pygame.mouse.get_pos()
            self.x = mouse_x - self.offset_x
            self.y = mouse_y - self.offset_y
            
        # �߽��飨�����ϳ���Ļ̫Զ��
        self.x = max(-self.width//2, min(self.x, SCREEN_WIDTH - self.width//2))
        self.y = max(-self.height//2, min(self.y, SCREEN_HEIGHT - self.height//2))

        # ��Ծ����
        if self.state == "jump":
            self.y += self.vel_y
            self.vel_y += self.gravity
            if self.vel_y > 0 and self.y >= SCREEN_HEIGHT // 2 - self.height // 2: # ���
                self.y = SCREEN_HEIGHT // 2 - self.height // 2
                self.vel_y = 0
                self.state = "idle"
                
        # ѹ�⶯��
        if self.squish_timer > 0:
            self.squish_timer -= 1
            if self.squish_timer == 0:
                self.state = "idle"
                
        # ��������
        if self.shake_timer > 0:
            self.shake_timer -= 1
            if self.shake_timer == 0:
                self.state = "idle"
                
        # ���ݼ�ʱ
        if self.show_bubble:
            self.bubble_timer -= 1
            if self.bubble_timer <= 0:
                self.show_bubble = False

    def draw(self, surface):
        # �����߼�
        render_img = self.image.copy()
        
        # Ӧ�ö�������
        if self.state == "squish" and self.squish_timer > 0:
            # �������죬����ѹ��
            new_w = int(self.width * 1.2)
            new_h = int(self.height * 0.8)
            render_img = pygame.transform.scale(render_img, (new_w, new_h))
        elif self.state == "shake" and self.shake_timer > 0:
            # ��΢λ�ƶ���
            offset = math.sin(pygame.time.get_ticks() * 0.5) * 3
            surface.blit(render_img, (self.x + offset, self.y))
            return
        
        surface.blit(render_img, (self.x, self.y))
        
        # ��������
        if self.show_bubble:
            self.draw_bubble(surface)

    def draw_bubble(self, surface):
        text_surf = font.render(self.bubble_text, True, BLACK)
        pad = 8
        w = text_surf.get_width() + pad * 2
        h = text_surf.get_height() + pad * 2
        
        bx = self.x + self.width // 2 - w // 2
        by = self.y - h - 10
        
        # ��ֹ���ݷɳ���Ļ����
        if by < 0:
            by = self.y + self.height + 10
            
        # �������ݿ�
        bubble_rect = pygame.Rect(bx, by, w, h)
        pygame.draw.rect(surface, BUBBLE_COLOR, bubble_rect, border_radius=8)
        pygame.draw.rect(surface, BLACK, bubble_rect, 2, border_radius=8)
        
        # С����
        tip_y = by - 5 if by < self.y else by + h + 5
        points = [
            (self.x + self.width // 2, self.y + (self.height if by < self.y else -10)),
            (self.x + self.width // 2 - 6, tip_y),
            (self.x + self.width // 2 + 6, tip_y)
        ]
        pygame.draw.polygon(surface, BUBBLE_COLOR, points)
        pygame.draw.polygon(surface, BLACK, points, 2)
        
        surface.blit(text_surf, (bx + pad, by + pad))

# ʵ����
pet = DesktopPet()

# ��ѭ��
running = True
while running:
    for event in pygame.event.get():
        if event.type == pygame.QUIT:
            running = False
        pet.handle_event(event)

    pet.update()
    
    # ���� (͸��)
    screen.fill((0,0,0,0))
    
    pet.draw(screen)
    
    pygame.display.flip()
    clock.tick(FPS)

pygame.quit()
sys.exit()